class Solution:
  def findBridges(self, graph):
    n = len(graph)
    visited = [False] * n
    low = [0] * n
    disc = [0] * n
    time = 0
    parent = [-1] * n
    for i in range(n):
      if not visited[i]:
        self.dfs(graph, i, -1, 0, visited, low, disc, time, parent)
    bridges = []
    for i in range(n):
      if disc[i] == low[i]:
        bridges.append([parent[i], i])
    return bridges
  def dfs(self, graph, vertex, parent, time, visited, low, disc, timeCounter, parentArr):
    disc[vertex] = time
    low[vertex] = time
    timeCounter[0] += 1
    time = timeCounter[0]
    visited[vertex] = True
    for neighbor in graph[vertex]:
      if neighbor == parent: continue
      if not visited[neighbor]:
        self.dfs(graph, neighbor, vertex, time, visited, low, disc, timeCounter, parentArr)
        low[vertex] = min(low[vertex], low[neighbor])
        if low[neighbor] >= disc[vertex]:
          bridges.append([vertex, neighbor])
      else:
        low[vertex] = min(low[vertex], disc[neighbor])

