class Solution {
  vector<vector<int>> findBridges(vector<vector<int>>& graph) {
    int n = graph.size();
    vector<bool> visited(n, false);
    vector<int> low(n, 0);
    vector<int> disc(n, 0);
    int time = 0;
    int parent = -1;
    vector<vector<int>> bridges;
    for (int i = 0; i < n; i++) {
      if (!visited[i]) {
        dfs(graph, i, -1, 0, visited, low, disc, time, parent, bridges);
      }
    }
    return bridges;
  }
  void dfs(vector<vector<int>>& graph, int vertex, int parent, int time, vector<bool>& visited, vector<int>& low, vector<int>& disc, int& timeCounter, int& parentArr) {
    disc[vertex] = time;
    low[vertex] = time;
    timeCounter++;
    time = timeCounter;
    visited[vertex] = true;
    for (int neighbor : graph[vertex]) {
      if (neighbor == parent) continue;
      if (!visited[neighbor]) {
        dfs(graph, neighbor, vertex, time, visited, low, disc, timeCounter, parentArr);
        low[vertex] = min(low[vertex], low[neighbor]);
        if (low[neighbor] >= disc[vertex]) {
          bridges.push_back({vertex, neighbor});
        }
      } else {
        low[vertex] = min(low[vertex], disc[neighbor]);
      }
    }
  }
};
